constexpr bool is_alphabetic(std::uint32_t scalar) noexcept
{
    return in_ranges(scalar, alphabetic_ranges);
}

constexpr bool is_lowercase(std::uint32_t scalar) noexcept
{
    return in_ranges(scalar, lowercase_ranges);
}

