inline constexpr auto lowercase_simple_mappings_page_index = make_source_mapping_page_index(lowercase_simple_mappings);
inline constexpr auto lowercase_simple_mappings_delta_ranges = make_simple_case_delta_ranges(lowercase_simple_mappings);
inline constexpr auto lowercase_simple_mappings_delta_ranges_page_slices =
    make_overlapping_range_page_slices(lowercase_simple_mappings_delta_ranges.ranges, lowercase_simple_mappings_delta_ranges.count);

constexpr const unicode_simple_case_delta_range* lowercase_simple_delta_range(std::uint32_t scalar) noexcept
{
    const auto index = find_overlapping_range_index_paged(
        scalar,
        lowercase_simple_mappings_delta_ranges.ranges,
        lowercase_simple_mappings_delta_ranges.count,
        lowercase_simple_mappings_delta_ranges_page_slices);
    if (index == lowercase_simple_mappings_delta_ranges.count)
    {
        return nullptr;
    }

    const auto& range = lowercase_simple_mappings_delta_ranges.ranges[index];
    const auto offset = scalar - range.first;
    return (range.stride != 0 && offset % range.stride == 0) ? &range : nullptr;
}


constexpr const unicode_simple_case_mapping* lowercase_simple_mapping(std::uint32_t scalar) noexcept
{
    return find_source_mapping_paged(scalar, lowercase_simple_mappings, lowercase_simple_mappings_page_index);
}

