    make_overlapping_range_page_slices(canonical_combining_class_ranges);

constexpr std::uint8_t canonical_combining_class(std::uint32_t scalar) noexcept
{
    const auto index = find_overlapping_range_index_paged(
        scalar,
        canonical_combining_class_ranges,
        canonical_combining_class_ranges.size(),
        canonical_combining_class_ranges_page_slices);
    if (index == canonical_combining_class_ranges.size())
    {
        return 0u;
    }
    return canonical_combining_class_ranges[index].canonical_combining_class;
}

constexpr unicode_grapheme_properties grapheme_properties(std::uint32_t scalar) noexcept
{
    const auto index = find_grapheme_property_range_index(scalar, grapheme_properties_ranges);
    if (index != grapheme_properties_ranges.size())
    {
        return grapheme_properties_ranges[index].properties;
    }

    return unicode_grapheme_properties{
        grapheme_cluster_break_property::other,
        indic_conjunct_break_property::none,
        false
    };
}

constexpr grapheme_cluster_break_property grapheme_cluster_break(std::uint32_t scalar) noexcept
{
    return grapheme_properties(scalar).break_property;
}

constexpr bool is_extended_pictographic(std::uint32_t scalar) noexcept
{
    return grapheme_properties(scalar).extended_pictographic;
}

constexpr indic_conjunct_break_property indic_conjunct_break(std::uint32_t scalar) noexcept
{
    return grapheme_properties(scalar).indic_property;
}

